import type { Metadata } from "next";
import ProfileClient from "./ProfileClient";

export const metadata: Metadata = {
  title: "プロフィール · Gunjo Test",
  description: "@gunjo/ui で構築したユーザープロフィールページ",
};

export default function ProfilePage() {
  return <ProfileClient />;
}

"use client";

import * as React from "react";
import {
  Avatar,
  AvatarImage,
  AvatarFallback,
  AvatarGroup,
  Statistic,
  MetadataList,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  Badge,
  Separator,
  Button,
  Input,
  Textarea,
  Dialog,
  DialogTrigger,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  DialogClose,
  Form,
  FormField,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
} from "@gunjo/ui";
import {
  IconMapPin,
  IconLink,
  IconCalendar,
  IconBriefcase,
  IconMail,
  IconCheck,
  IconRocket,
  IconGitMerge,
  IconStar,
} from "@tabler/icons-react";

type Profile = {
  name: string;
  handle: string;
  bio: string;
  location: string;
  website: string;
  email: string;
};

const INITIAL_PROFILE: Profile = {
  name: "田中 美奈",
  handle: "minat",
  bio: "穏やかなインターフェースをつくるデザインエンジニア。お茶と、書体と、小さな道具が好き。",
  location: "京都",
  website: "https://mina.example.dev",
  email: "mina@example.dev",
};

const POSTS = [
  {
    id: 1,
    title: "もっと穏やかな設定ページへ",
    excerpt:
      "3つのモーダルを廃止して、インライン編集に置き換えました。保存ステップのコンバージョンが12%向上しました。",
    tag: "デザイン",
    tagVariant: "secondary" as const,
    time: "2日",
    likes: 128,
  },
  {
    id: 2,
    title: "トークンはパレットではなく、約束ごと",
    excerpt:
      "テーマが2つ以上になると、なぜ生の色よりセマンティックトークン（success / destructive）が優れているのか、短い覚え書き。",
    tag: "エンジニアリング",
    tagVariant: "outline" as const,
    time: "5日",
    likes: 96,
  },
  {
    id: 3,
    title: "375pxテスト",
    excerpt:
      "ヘッダー、統計、タブが375pxのビューポートで崩れるなら、それは出荷できません。わたしのチェックリストを紹介します。",
    tag: "モバイル",
    tagVariant: "default" as const,
    time: "1週間",
    likes: 211,
  },
];

const MUTUALS = [
  { name: "佐藤 あき", initials: "佐" },
  { name: "小林 武", initials: "小" },
  { name: "伊藤 千夏", initials: "伊" },
  { name: "山下 大", initials: "山" },
  { name: "藤井 恵美", initials: "藤" },
  { name: "林 ふみ", initials: "林" },
];

export default function ProfileClient() {
  const [profile, setProfile] = React.useState<Profile>(INITIAL_PROFILE);
  const [following, setFollowing] = React.useState(false);
  const [tab, setTab] = React.useState("posts");
  const [editOpen, setEditOpen] = React.useState(false);

  const baseFollowers = 4820;
  const followers = baseFollowers + (following ? 1 : 0);

  const initials = profile.name
    .split(" ")
    .map((p) => p[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();

  const websiteLabel = profile.website.replace(/^https?:\/\//, "");

  return (
    <main className="mx-auto w-full max-w-3xl px-4 py-8 sm:px-6">
      {/* ---------- Header ---------- */}
      <section
        aria-label="プロフィールヘッダー"
        className="rounded-xl border border-border bg-card p-5 text-card-foreground sm:p-6"
      >
        <div className="flex flex-col gap-5 sm:flex-row sm:items-start sm:justify-between">
          <div className="flex items-start gap-4">
            <Avatar
              className="h-16 w-16 sm:h-20 sm:w-20"
              presence="online"
              presenceLabel="オンライン"
            >
              {/* Intentionally broken src to exercise the fallback */}
              <AvatarImage src="/does-not-exist.png" alt={profile.name} />
              <AvatarFallback>{initials}</AvatarFallback>
            </Avatar>

            <div className="min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <h1 className="text-xl font-bold tracking-tight">
                  {profile.name}
                </h1>
                <Badge variant="secondary" className="gap-1">
                  <IconCheck className="h-3 w-3" aria-hidden />
                  認証済み
                </Badge>
              </div>
              <p className="text-sm text-muted-foreground">@{profile.handle}</p>
              <p className="mt-2 max-w-prose text-sm text-foreground">
                {profile.bio}
              </p>

              <div className="mt-3 flex flex-wrap items-center gap-x-4 gap-y-1 text-sm text-muted-foreground">
                <span className="inline-flex items-center gap-1">
                  <IconMapPin className="h-4 w-4" aria-hidden />
                  {profile.location}
                </span>
                <a
                  href={profile.website}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-1 text-foreground underline-offset-4 hover:underline"
                >
                  <IconLink className="h-4 w-4" aria-hidden />
                  {websiteLabel}
                </a>
                <span className="inline-flex items-center gap-1">
                  <IconCalendar className="h-4 w-4" aria-hidden />
                  2021年3月に登録
                </span>
              </div>
            </div>
          </div>

          <div className="flex shrink-0 items-center gap-2">
            <Button
              variant={following ? "outline" : "default"}
              onClick={() => setFollowing((v) => !v)}
              aria-pressed={following}
            >
              {following ? "フォロー中" : "フォロー"}
            </Button>
            <EditProfileDialog
              open={editOpen}
              onOpenChange={setEditOpen}
              profile={profile}
              onSave={(next) => {
                setProfile(next);
                setEditOpen(false);
              }}
            />
          </div>
        </div>

        {/* Stats */}
        <div className="mt-6 grid grid-cols-3 gap-3">
          <Statistic label="フォロワー" value={followers.toLocaleString()} />
          <Statistic label="フォロー中" value="312" />
          <Statistic
            label="投稿"
            value="1,204"
            change="+18"
            trend="up"
            hint="今月"
          />
        </div>

        {/* Mutual connections */}
        <div className="mt-5 flex flex-wrap items-center gap-3">
          <AvatarGroup
            max={4}
            overflowAriaLabel={`ほか${MUTUALS.length - 4}人の共通のつながりを表示`}
            overflowContent={
              <div className="p-3">
                <p className="mb-2 px-1 text-xs font-medium text-muted-foreground">
                  共通のつながり
                </p>
                <ul className="space-y-1">
                  {MUTUALS.map((m) => (
                    <li
                      key={m.name}
                      className="flex items-center gap-2 rounded-md px-1 py-1 text-sm"
                    >
                      <Avatar className="h-6 w-6">
                        <AvatarFallback className="text-[10px]">
                          {m.initials}
                        </AvatarFallback>
                      </Avatar>
                      {m.name}
                    </li>
                  ))}
                </ul>
              </div>
            }
          >
            {MUTUALS.map((m) => (
              <Avatar key={m.name} tooltip={m.name}>
                <AvatarFallback className="text-xs">{m.initials}</AvatarFallback>
              </Avatar>
            ))}
          </AvatarGroup>
          <span className="text-sm text-muted-foreground">
            あきさん、武さん、ほか知り合い{MUTUALS.length - 2}人がフォローしています
          </span>
        </div>
      </section>

      {/* ---------- Tabs ---------- */}
      <div className="mt-6">
        <Tabs value={tab} onValueChange={setTab}>
          <TabsList className="w-full justify-start overflow-x-auto">
            <TabsTrigger value="posts">投稿</TabsTrigger>
            <TabsTrigger value="about">概要</TabsTrigger>
            <TabsTrigger value="activity">アクティビティ</TabsTrigger>
          </TabsList>

          {/* Posts */}
          <TabsContent value="posts">
            <div className="flex flex-col gap-4">
              {POSTS.map((post) => (
                <Card key={post.id}>
                  <CardHeader>
                    <div className="flex items-center justify-between gap-2">
                      <CardTitle className="text-base">{post.title}</CardTitle>
                      <Badge variant={post.tagVariant}>{post.tag}</Badge>
                    </div>
                    <CardDescription>{post.excerpt}</CardDescription>
                  </CardHeader>
                  <Separator />
                  <CardFooter className="justify-between pt-4 text-sm text-muted-foreground">
                    <span className="inline-flex items-center gap-1">
                      <IconStar className="h-4 w-4" aria-hidden />
                      いいね {post.likes}
                    </span>
                    <span>{post.time}前</span>
                  </CardFooter>
                </Card>
              ))}
            </div>
          </TabsContent>

          {/* About */}
          <TabsContent value="about">
            <Card>
              <CardHeader>
                <CardTitle className="text-base">プロフィール詳細</CardTitle>
                <CardDescription>
                  プロフィールに表示される公開情報です。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <MetadataList
                  items={[
                    {
                      label: "役職",
                      value: "デザインエンジニア",
                      icon: <IconBriefcase className="h-4 w-4" />,
                    },
                    {
                      label: "所在地",
                      value: profile.location,
                      icon: <IconMapPin className="h-4 w-4" />,
                    },
                    {
                      label: "メール",
                      value: profile.email,
                      icon: <IconMail className="h-4 w-4" />,
                    },
                    {
                      label: "ウェブサイト",
                      value: websiteLabel,
                      icon: <IconLink className="h-4 w-4" />,
                    },
                    {
                      label: "登録",
                      value: "2021年3月",
                      description: "プラットフォーム歴5年以上",
                      icon: <IconCalendar className="h-4 w-4" />,
                    },
                  ]}
                />
              </CardContent>
            </Card>
          </TabsContent>

          {/* Activity */}
          <TabsContent value="activity">
            <Card>
              <CardHeader>
                <CardTitle className="text-base">最近のアクティビティ</CardTitle>
              </CardHeader>
              <CardContent>
                <Timeline>
                  <TimelineItem
                    variant="active"
                    marker={<IconRocket className="h-4 w-4 text-primary" />}
                  >
                    <TimelineTime>今日</TimelineTime>
                    <TimelineTitle>プロフィール v2 を公開</TimelineTitle>
                    <TimelineDescription>
                      刷新したプロフィールヘッダーを全ユーザーに展開しました。
                    </TimelineDescription>
                  </TimelineItem>
                  <TimelineItem variant="default">
                    <TimelineTime>2日前</TimelineTime>
                    <TimelineTitle>3件のプルリクエストをマージ</TimelineTitle>
                    <TimelineDescription>
                      表示レイヤー全体のトークンを整理しました。
                    </TimelineDescription>
                  </TimelineItem>
                  <TimelineItem
                    variant="muted"
                    marker={<IconGitMerge className="h-4 w-4 text-muted-foreground" />}
                  >
                    <TimelineTime>先週</TimelineTime>
                    <TimelineTitle>フォロワーが4,800人に到達</TimelineTitle>
                    <TimelineDescription>
                      フォローしてくれてありがとう。
                    </TimelineDescription>
                  </TimelineItem>
                  <TimelineItem variant="outline" connector={false}>
                    <TimelineTime>2021年3月</TimelineTime>
                    <TimelineTitle>プラットフォームに登録</TimelineTitle>
                  </TimelineItem>
                </Timeline>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </main>
  );
}

/* ---------------- Edit Profile Dialog with validation ---------------- */

type Errors = Partial<Record<keyof Profile, string>>;

function validate(values: Profile): Errors {
  const errors: Errors = {};
  if (!values.name.trim()) {
    errors.name = "名前を入力してください。";
  } else if (values.name.trim().length > 50) {
    errors.name = "名前は50文字以内で入力してください。";
  }
  if (!values.handle.trim()) {
    errors.handle = "ハンドルを入力してください。";
  } else if (!/^[a-zA-Z0-9_]+$/.test(values.handle.trim())) {
    errors.handle = "半角英数字とアンダースコアのみ使用できます。";
  }
  if (values.bio.length > 160) {
    errors.bio = "自己紹介は160文字以内で入力してください。";
  }
  if (values.website.trim() && !/^https?:\/\/.+\..+/.test(values.website.trim())) {
    errors.website = "有効なURLを入力してください（http:// または https:// で始まる形式）。";
  }
  if (values.email.trim() && !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(values.email.trim())) {
    errors.email = "有効なメールアドレスを入力してください。";
  }
  return errors;
}

function EditProfileDialog({
  open,
  onOpenChange,
  profile,
  onSave,
}: {
  open: boolean;
  onOpenChange: (v: boolean) => void;
  profile: Profile;
  onSave: (p: Profile) => void;
}) {
  const [values, setValues] = React.useState<Profile>(profile);
  const [errors, setErrors] = React.useState<Errors>({});
  const [submitted, setSubmitted] = React.useState(false);

  // Reset the draft whenever the dialog (re)opens
  React.useEffect(() => {
    if (open) {
      setValues(profile);
      setErrors({});
      setSubmitted(false);
    }
  }, [open, profile]);

  const liveErrors = submitted ? validate(values) : errors;

  const set =
    (key: keyof Profile) =>
    (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      const next = { ...values, [key]: e.target.value };
      setValues(next);
      if (submitted) setErrors(validate(next));
    };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const found = validate(values);
    setErrors(found);
    setSubmitted(true);
    if (Object.keys(found).length === 0) {
      onSave({
        ...values,
        name: values.name.trim(),
        handle: values.handle.trim(),
        website: values.website.trim(),
        email: values.email.trim(),
      });
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogTrigger asChild>
        <Button variant="outline">プロフィールを編集</Button>
      </DialogTrigger>
      <DialogContent className="max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>プロフィールを編集</DialogTitle>
          <DialogDescription>
            公開プロフィールを更新します。変更は全員に表示されます。
          </DialogDescription>
        </DialogHeader>

        <Form onSubmit={handleSubmit} noValidate>
          <FormField className="p-0">
            <FormLabel htmlFor="edit-name">表示名</FormLabel>
            <FormControl>
              <Input
                id="edit-name"
                value={values.name}
                onChange={set("name")}
                aria-invalid={!!liveErrors.name}
                aria-describedby={liveErrors.name ? "edit-name-error" : undefined}
              />
            </FormControl>
            {liveErrors.name ? (
              <FormMessage id="edit-name-error">{liveErrors.name}</FormMessage>
            ) : null}
          </FormField>

          <FormField className="p-0">
            <FormLabel htmlFor="edit-handle">ハンドル</FormLabel>
            <FormControl>
              <Input
                id="edit-handle"
                value={values.handle}
                onChange={set("handle")}
                aria-invalid={!!liveErrors.handle}
                aria-describedby={
                  liveErrors.handle ? "edit-handle-error" : undefined
                }
              />
            </FormControl>
            {liveErrors.handle ? (
              <FormMessage id="edit-handle-error">
                {liveErrors.handle}
              </FormMessage>
            ) : (
              <FormDescription>あなた固有の @ユーザー名です。</FormDescription>
            )}
          </FormField>

          <FormField className="p-0">
            <FormLabel htmlFor="edit-bio">自己紹介</FormLabel>
            <FormControl>
              <Textarea
                id="edit-bio"
                rows={3}
                value={values.bio}
                onChange={set("bio")}
                aria-invalid={!!liveErrors.bio}
                aria-describedby="edit-bio-help"
              />
            </FormControl>
            <FormDescription id="edit-bio-help">
              {values.bio.length}/160文字
            </FormDescription>
            {liveErrors.bio ? (
              <FormMessage>{liveErrors.bio}</FormMessage>
            ) : null}
          </FormField>

          <FormField className="p-0">
            <FormLabel htmlFor="edit-website">ウェブサイト</FormLabel>
            <FormControl>
              <Input
                id="edit-website"
                type="url"
                value={values.website}
                onChange={set("website")}
                aria-invalid={!!liveErrors.website}
                aria-describedby={
                  liveErrors.website ? "edit-website-error" : undefined
                }
              />
            </FormControl>
            {liveErrors.website ? (
              <FormMessage id="edit-website-error">
                {liveErrors.website}
              </FormMessage>
            ) : null}
          </FormField>

          <FormField className="p-0">
            <FormLabel htmlFor="edit-email">メール</FormLabel>
            <FormControl>
              <Input
                id="edit-email"
                type="email"
                value={values.email}
                onChange={set("email")}
                aria-invalid={!!liveErrors.email}
                aria-describedby={
                  liveErrors.email ? "edit-email-error" : undefined
                }
              />
            </FormControl>
            {liveErrors.email ? (
              <FormMessage id="edit-email-error">{liveErrors.email}</FormMessage>
            ) : null}
          </FormField>

          <DialogFooter>
            <DialogClose asChild>
              <Button type="button" variant="ghost">
                キャンセル
              </Button>
            </DialogClose>
            <Button type="submit">変更を保存</Button>
          </DialogFooter>
        </Form>
      </DialogContent>
    </Dialog>
  );
}
